import React from "react";

function QuestionPanel() {
  return (
    <div className="question-panel">
      <h3>Question</h3>
      <p>
        Write a SQL query to fetch all employees whose salary is greater than
        50,000.
      </p>
    </div>
  );
}

export default QuestionPanel;
